import React, { useState, useRef, useEffect } from 'react';

export default function SlidingTabs({ tabs, onChange }) {
  const [activeTab, setActiveTab] = useState(tabs[0]?.key || '');
  const [coords, setCoords] = useState({ left: 0, width: 0 });
  const activeTabRef = useRef(null);

  const handleTabClick = (tab) => {
    if (tab.disabled) return;
    setActiveTab(tab.key);
    if (onChange) onChange(tab.key);
  };

  useEffect(() => {
    if (activeTabRef.current) {
      const { offsetLeft, offsetWidth } = activeTabRef.current;
      setCoords({ left: offsetLeft, width: offsetWidth });
    }
  }, [activeTab]);

  return (
    <div className="relative flex p-1 bg-gray-100 rounded-xl max-w-max border border-gray-200">
      {/* Sliding Underline / Background highlighting element */}
      <div
        className="absolute bottom-1 top-1 bg-white rounded-lg shadow-sm transition-all duration-300 ease-out"
        style={{ left: coords.left, width: coords.width }}
      />

      {tabs.map((tab) => {
        const isActive = activeTab === tab.key;
        return (
          <button
            key={tab.key}
            onClick={() => handleTabClick(tab)}
            ref={isActive ? activeTabRef : null}
            disabled={tab.disabled}
            className={`relative z-10 px-4 py-2 text-sm font-semibold rounded-lg flex items-center gap-2 select-none focus:outline-none transition ${
              tab.disabled
                ? 'opacity-40 cursor-not-allowed text-gray-400'
                : isActive
                ? 'text-purple-700'
                : 'text-gray-500 hover:text-gray-800'
            }`}
          >
            <span>{tab.label}</span>
            {tab.badge !== undefined && (
              <span className={`text-xs px-2 py-0.5 rounded-full ${isActive ? 'bg-purple-100 text-purple-700' : 'bg-gray-200 text-gray-600'}`}>
                {tab.badge}
              </span>
            )}
          </button>
        );
      })}
    </div>
  );
}
